    #[test]
    fn test_otlp_122_trace_id_validation_logic() {
        // Test trace ID validation functions directly

        // Valid trace IDs
        assert!(is_valid_trace_id_format(VALID_TRACE_ID_1));
        assert!(is_valid_trace_id_format(VALID_TRACE_ID_2));
        assert!(is_valid_trace_id_format(VALID_TRACE_ID_3));
        assert!(is_valid_trace_id_format("abcdef1234567890abcdef1234567890"));

        // All-zero trace ID (valid format but semantically invalid per W3C)
        assert!(is_valid_trace_id_format(ALL_ZERO_TRACE_ID));
        assert!(is_all_zero_trace_id(ALL_ZERO_TRACE_ID));

        // Invalid formats
        assert!(!is_valid_trace_id_format("")); // Empty
        assert!(!is_valid_trace_id_format("short")); // Too short
        assert!(!is_valid_trace_id_format(
            "4bf92f3577b34da6a3ce929d0e0e4736TOOLONG"
        )); // Too long
        assert!(!is_valid_trace_id_format(
            "4bf92f3577b34da6a3ce929d0e0eXYZ!"
        )); // Invalid hex chars
        assert!(!is_valid_trace_id_format(
            "gggggggggggggggggggggggggggggggg"
        )); // Invalid hex chars

        // Non-zero trace IDs should not be detected as all-zero
        assert!(!is_all_zero_trace_id(VALID_TRACE_ID_1));
        assert!(!is_all_zero_trace_id(VALID_TRACE_ID_2));
        assert!(!is_all_zero_trace_id("00000000000000000000000000000001")); // Almost zero

        println!("OTLP-122: Trace ID validation logic verified");
    }

    // OTLP-124: Empty ArrayValue validation conformance test
    // This test validates that when an exporter sees a span with attribute value type
    // ArrayValue but elements_count=0 (empty array), it MUST be valid (empty arrays are legal).

    #[derive(Debug, Clone)]
    struct Otlp124Scenario {
        name: String,
        span_name: String,
        trace_id: String,
        span_id: String,
        attributes: Vec<(String, Otlp124AttributeValue)>,
        expected_valid: bool,
        description: String,
    }

    #[derive(Debug, Clone)]
    enum Otlp124AttributeValue {
        String(String),
        ArrayEmpty,                 // Empty array with elements_count=0
        ArrayNonEmpty(Vec<String>), // Non-empty array for comparison
    }

    impl Otlp124Scenario {
        fn new(
            name: &str,
            span_name: &str,
            trace_id: &str,
            span_id: &str,
            attributes: Vec<(String, Otlp124AttributeValue)>,
            expected_valid: bool,
            description: &str,
        ) -> Self {
            Self {
                name: name.to_string(),
                span_name: span_name.to_string(),
                trace_id: trace_id.to_string(),
                span_id: span_id.to_string(),
                attributes,
                expected_valid,
                description: description.to_string(),
            }
        }
    }

    fn validate_otlp_124_scenario(scenario: &Otlp124Scenario) -> bool {
        println!("OTLP-124: Testing scenario '{}'", scenario.name);

        // Validate the attributes according to OTLP spec
        for (attr_name, attr_value) in &scenario.attributes {
            match attr_value {
                Otlp124AttributeValue::ArrayEmpty => {
                    // Empty arrays MUST be valid according to OTLP-124
                    println!(
                        "  Found empty ArrayValue attribute '{}' - MUST be valid",
                        attr_name
                    );
                }
                Otlp124AttributeValue::ArrayNonEmpty(values) => {
                    println!(
                        "  Found non-empty ArrayValue attribute '{}' with {} elements",
                        attr_name,
                        values.len()
                    );
                }
                Otlp124AttributeValue::String(value) => {
                    println!("  Found String attribute '{}': '{}'", attr_name, value);
                }
            }
        }

        // Per OTLP-124: Empty arrays (elements_count=0) MUST be valid
        let all_arrays_valid = scenario.attributes.iter().all(|(_, value)| {
            match value {
                Otlp124AttributeValue::ArrayEmpty => true, // Empty arrays are valid
                Otlp124AttributeValue::ArrayNonEmpty(_) => true, // Non-empty arrays are valid
                Otlp124AttributeValue::String(_) => true,  // String attributes are valid
            }
        });

        let result = all_arrays_valid == scenario.expected_valid;

        if result {
            println!("  ✓ PASS: {}", scenario.description);
        } else {
            println!("  ✗ FAIL: {}", scenario.description);
        }

        result
    }

