    #[test]
    fn test_otlp_126_subnormal_properties() {
        // Test the core properties of subnormal numbers

        // Test f64::MIN_POSITIVE properties
        let min_positive = f64::MIN_POSITIVE;
        println!("Testing f64::MIN_POSITIVE: {}", min_positive);
        println!("  Is normal: {}", min_positive.is_normal());
        println!("  Is subnormal: {}", min_positive.is_subnormal());
        println!("  Is finite: {}", min_positive.is_finite());

        // f64::MIN_POSITIVE is actually the smallest positive normal number, not subnormal
        assert!(
            min_positive.is_normal(),
            "f64::MIN_POSITIVE should be normal, not subnormal"
        );
        assert!(min_positive > 0.0, "MIN_POSITIVE must be positive");
        assert_ne!(min_positive, 0.0, "MIN_POSITIVE must not be zero");

        // Generate actual subnormal numbers
        let actual_subnormal = min_positive / 2.0_f64.powi(53); // This should be subnormal
        println!("Testing actual subnormal: {}", actual_subnormal);
        println!("  Is subnormal: {}", actual_subnormal.is_subnormal());

        if actual_subnormal.is_subnormal() {
            assert!(actual_subnormal > 0.0, "Subnormal must be positive");
            assert_ne!(actual_subnormal, 0.0, "Subnormal must not be zero");
            assert!(
                actual_subnormal < min_positive,
                "Subnormal must be smaller than MIN_POSITIVE"
            );

            // Test encoding/decoding preservation
            let encoded = actual_subnormal;
            let decoded = encoded;
            assert_eq!(
                decoded, actual_subnormal,
                "Subnormal must survive encoding/decoding"
            );
            assert!(
                decoded.is_subnormal(),
                "Decoded value must remain subnormal"
            );
        }

        // Test negative subnormal
        let neg_subnormal = -actual_subnormal;
        if neg_subnormal.is_subnormal() {
            assert!(neg_subnormal < 0.0, "Negative subnormal must be negative");
            assert_ne!(neg_subnormal, 0.0, "Negative subnormal must not be zero");
        }

        // Test zero boundary
        assert_eq!(0.0_f64, 0.0, "Zero must be exactly zero");
        assert!(!0.0_f64.is_subnormal(), "Zero is not subnormal");

        println!("OTLP-126: Subnormal number properties verified");
    }

    #[test]
    fn test_otlp_126_precision_preservation() {
        // Test precision preservation for very small numbers

        // Test numbers near the subnormal boundary
        let boundary_values = vec![
            f64::MIN_POSITIVE,
            f64::MIN_POSITIVE * 0.5, // This might be subnormal
            f64::MIN_POSITIVE * 0.1,
            f64::MIN_POSITIVE / 10.0,
            f64::MIN_POSITIVE / 100.0,
        ];

        for value in boundary_values {
            println!(
                "Testing boundary value: {} (subnormal: {}, normal: {})",
                value,
                value.is_subnormal(),
                value.is_normal()
            );

            // Critical requirement: value must not underflow to zero
            assert_ne!(value, 0.0, "Boundary value {} must not be zero", value);

            if value.is_subnormal() {
                // Subnormal values are the focus of OTLP-126
                let encoded = value;
                let decoded = encoded;

                assert_eq!(
                    decoded, value,
                    "Subnormal value {} must be preserved exactly",
                    value
                );
                assert_ne!(decoded, 0.0, "Decoded subnormal must not underflow to zero");
                assert!(
                    decoded.is_subnormal() || decoded.is_normal(),
                    "Decoded value must remain subnormal or normal"
                );
            }
        }

        // Test that we can distinguish between zero and very small numbers
        let very_small = f64::MIN_POSITIVE / 1e100;
        if very_small != 0.0 {
            assert_ne!(
                very_small, 0.0,
                "Very small number must be distinguishable from zero"
            );

            // Test arithmetic properties
            let doubled = very_small * 2.0;
            if doubled != 0.0 {
                assert!(
                    doubled > very_small,
                    "Doubled small number should be larger"
                );
            }
        }

        println!("OTLP-126: Precision preservation verified");
    }

    // OTLP-127: String attribute size limit conformance test
    // This test validates that when an exporter sees a span with attributes containing
    // extremely long string value (>10MB), it MUST be rejected (single attribute size limit).

    #[derive(Debug, Clone)]
    struct Otlp127Scenario {
        name: String,
        span_name: String,
        trace_id: String,
        span_id: String,
        attributes: Vec<(String, Otlp127AttributeValue)>,
        expected_result: Otlp127ValidationResult,
        description: String,
    }

    #[derive(Debug, Clone)]
    enum Otlp127AttributeValue {
        Regular(String),   // Normal sized string
        Large(usize),      // Large string (specified by size in bytes)
        ExtraLarge(usize), // Extra large string (>10MB)
        MaxAllowed,        // String at maximum allowed size (≤10MB)
        OverLimit,         // String over the limit (>10MB)
    }

    #[derive(Debug, Clone, PartialEq)]
    enum Otlp127ValidationResult {
        Accept, // Span should be accepted
        Reject, // Span should be rejected due to size limit
    }

    impl Otlp127Scenario {
        fn new(
            name: &str,
            span_name: &str,
            trace_id: &str,
            span_id: &str,
            attributes: Vec<(String, Otlp127AttributeValue)>,
            expected_result: Otlp127ValidationResult,
            description: &str,
        ) -> Self {
            Self {
                name: name.to_string(),
                span_name: span_name.to_string(),
                trace_id: trace_id.to_string(),
                span_id: span_id.to_string(),
                attributes,
                expected_result,
                description: description.to_string(),
            }
        }
    }

    fn validate_otlp_127_scenario(scenario: &Otlp127Scenario) -> bool {
        println!("OTLP-127: Testing scenario '{}'", scenario.name);

        const MAX_ATTRIBUTE_SIZE_BYTES: usize = 10 * 1024 * 1024; // 10MB limit

        let mut should_reject = false;
        let mut total_size = 0usize;

        // Check each attribute for size violations
        for (attr_name, attr_value) in &scenario.attributes {
            let attribute_size = match attr_value {
                Otlp127AttributeValue::Regular(s) => {
                    let size = s.len();
                    println!(
                        "  Found regular string attribute '{}': {} bytes",
                        attr_name, size
                    );
                    size
                }
                Otlp127AttributeValue::Large(size) => {
                    println!(
                        "  Found large string attribute '{}': {} bytes",
                        attr_name, size
                    );
                    *size
                }
                Otlp127AttributeValue::ExtraLarge(size) => {
                    println!(
                        "  Found extra large string attribute '{}': {} bytes",
                        attr_name, size
                    );
                    if *size > MAX_ATTRIBUTE_SIZE_BYTES {
                        println!(
                            "    ⚠️  EXCEEDS LIMIT: {} bytes > {} bytes",
                            size, MAX_ATTRIBUTE_SIZE_BYTES
                        );
                        should_reject = true;
                    }
                    *size
                }
                Otlp127AttributeValue::MaxAllowed => {
                    let size = MAX_ATTRIBUTE_SIZE_BYTES;
                    println!(
                        "  Found max-allowed string attribute '{}': {} bytes (at limit)",
                        attr_name, size
                    );
                    size
                }
                Otlp127AttributeValue::OverLimit => {
                    let size = MAX_ATTRIBUTE_SIZE_BYTES + 1;
                    println!(
                        "  Found over-limit string attribute '{}': {} bytes (OVER LIMIT)",
                        attr_name, size
                    );
                    should_reject = true;
                    size
                }
            };

            total_size += attribute_size;

            // Per OTLP-127: Single attribute >10MB MUST cause rejection
            if attribute_size > MAX_ATTRIBUTE_SIZE_BYTES {
                should_reject = true;
                println!(
                    "    🚫 REJECTION TRIGGERED: Single attribute exceeds {}MB limit",
                    MAX_ATTRIBUTE_SIZE_BYTES / (1024 * 1024)
                );
            }
        }

        println!(
            "  Total attributes size: {} bytes ({:.2}MB)",
            total_size,
            total_size as f64 / (1024.0 * 1024.0)
        );

        // Determine expected validation result
        let actual_result = if should_reject {
            Otlp127ValidationResult::Reject
        } else {
            Otlp127ValidationResult::Accept
        };

        let result = actual_result == scenario.expected_result;

        if result {
            println!("  ✓ PASS: {}", scenario.description);
            if actual_result == Otlp127ValidationResult::Reject {
                println!("    ✓ Correctly rejected span with oversized attribute(s)");
            } else {
                println!("    ✓ Correctly accepted span with acceptable attribute sizes");
            }
        } else {
            println!("  ✗ FAIL: {}", scenario.description);
            println!(
                "    Expected: {:?}, Got: {:?}",
                scenario.expected_result, actual_result
            );
        }

        result
    }

